/* --- Main Toolbar Layout --- */
.rfq-toolbar {
  display: flex;
  align-items: center;
  padding: 0px 16px;
  background-color: #fff;
  border-bottom: 1px solid #e0e0e0;
  height: auto;
  min-height: 44px; /* Tightened: fits the 34px controls with minimal padding */
  box-sizing: border-box;
  flex-wrap: wrap; /* Allow wrapping on small screens */
  gap: 8px;
}

.toolbar-left, .toolbar-right {
  display: flex;
  align-items: center;
  gap: 8px;
}

.toolbar-spacer {
  flex: 1 1 auto;
}

.admin-group, .filter-group, .view-group, .utility-group, .bulk-status-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* --- Input & Field Styling --- */

.compact-field {
  width: 150px;
}

.wide-field {
  width: 180px;
}

.bulk-status-field {
  width: 135px;
}

/* Override Mat-Field to look like a box */
::ng-deep .mat-mdc-form-field-flex {
  align-items: center !important;
  background-color: #fff !important;
}

::ng-deep .mat-mdc-text-field-wrapper {
  background-color: #fff !important;
}

/* Center the select value AND the resting label vertically within the form field.
   Telling Material the true container height (34px) centers the RESTING (empty)
   label; leaving it at the default 56px while the infix was flex-shrunk dropped the
   empty "Status" placeholder to the bottom. That handles the empty state. */
::ng-deep .toolbar-field {
  --mat-form-field-container-height: 34px;

  .mat-mdc-form-field-infix {
    display: flex;
    align-items: center;
    min-height: 34px;
  }

  .mat-mdc-select {
    display: flex;
    align-items: center;
  }

  .mat-mdc-select-value {
    display: flex;
    align-items: center;
  }

  /* Pin the FLOATED label (populated Division/Status/View) so it straddles the
     outline border DETERMINISTICALLY, independent of font, DPR, and browser.
     Root cause of the "labels overflow above the field" bug: Material positions the
     outlined floated label with `line-height: normal` + `translateY(-106%/-34.75px)`,
     so its exact vertical spot depends on the rendered font's metrics AND on which of
     Material's two competing float-above rules wins. On environments where the label
     font resolved taller than our Inter (and/or the outlined -34.75px rule won), the
     label rode up out of the top of the field. Container-height alone does NOT fix
     this — the float position must be pinned. Fixing line-height gives the label a
     known height (12px after the 0.75 scale) and the explicit transform lands its
     centre on the border in every browser. Verified against the live sandbox: centre
     sits 0.3px from the border with no overflow. Do not remove without re-verifying
     on a machine where the toolbar font is NOT locally installed. */
  .mdc-floating-label {
    line-height: 16px !important;
  }

  .mdc-floating-label--float-above {
    transform: translateY(-24px) scale(0.75) !important;
  }
}

/* --- Button Styling --- */

/* Primary Pink Button */
.create-btn {
  background-color: #D81B60 !important; /* Brand Pink */
  color: #fff !important;
  border-radius: 4px;
  height: 34px;
